  } else if (factText.contains('Denizli') || factText.contains('Pamukkale') || factText.contains('Hierapolis') || factText.contains('Laodikeia')) {
    rawUrl = 'https://images.unsplash.com/photo-1504280390367-361c6d9f38f4?auto=format&fit=crop&w=400&q=70';
  } else if (factText.contains('Şanlıurfa') || factText.contains('Göbeklitepe') || factText.contains('Balıklıgöl') || factText.contains('Harran')) {
    rawUrl = 'https://images.unsplash.com/photo-1590001155093-a3c66ab0c3ff?auto=format&fit=crop&w=400&q=70';
  } else if (factText.contains('Muğla') || factText.contains('Fethiye') || factText.contains('Ölüdeniz') || factText.contains('Dalyan') || factText.contains('Kelebekler') || factText.contains('İztuzu') || factText.contains('Knidos') || factText.contains('Kaunos') || factText.contains('Tlos')) {
    rawUrl = 'https://images.unsplash.com/photo-1506929562872-bb421503ef21?auto=format&fit=crop&w=400&q=70';
  } else if (factText.contains('Bursa') || factText.contains('Cumalıkızık') || factText.contains('Gölyazı') || factText.contains('Oylat') || factText.contains('Uludağ')) {
